fn read_cmdline(pid: i32) -> String {
    let path = format!("/proc/{pid}/cmdline");
    fs::read(&path)
        .unwrap_or_default()
        .iter()
        .map(|&b| if b == 0 { ' ' } else { b as char })
        .collect::<String>()
        .trim()
        .to_string()
}
